# -*- coding: utf-8 -*-
# QUIZ5: balancing questions to bring thin modules (0,3,6,12,14,15,18) up to 9 each.
QUIZ5 = {0: [{'q': 'A sensor, a PLC, and a motor starter together form what basic control building block?', 'options': ['A network switch', 'An input → decision → output control loop', 'A safety relay', 'A SCADA server'], 'answer': 1, 'explain': 'Automation at its core is sense (input) → decide (controller logic) → act (output). Everything scales up from that loop.'}, {'q': 'Which document set does a tech reach for FIRST when troubleshooting an unfamiliar machine?', 'options': ['The vendor sales brochure', 'The electrical schematics / prints', 'The purchase order', 'The company handbook'], 'answer': 1, 'explain': 'Prints show power distribution, I/O addresses, and safety circuits — the map you follow to isolate a fault.'}, {'q': '"Mean Time To Repair" is driven down most by which AET skill?', 'options': ['Faster typing', 'Systematic troubleshooting and print literacy', 'Buying more spares', 'Working longer shifts'], 'answer': 1, 'explain': 'MTTR falls when a tech can read the system and localize the fault quickly instead of swapping parts blindly.'}], 3: [{'q': 'A CTD (count-down) counter reaches zero. Its done bit typically:', 'options': ['Stays off forever', 'Sets to signal the count is complete', 'Resets the PLC', 'Doubles the preset'], 'answer': 1, 'explain': 'CTU/CTD done bits set when ACC meets the preset condition, signaling downstream logic to act.'}, {'q': 'You need a one-shot pulse that fires for exactly one scan on a rising edge. Which instruction?', 'options': ['TON', 'ONS (one-shot)', 'LATCH', 'MOV'], 'answer': 1, 'explain': 'A one-shot (ONS) produces a single-scan true pulse on the transition, ideal for triggering counts or moves once.'}, {'q': 'An RTO (retentive timer) differs from a TON because it:', 'options': ['Runs faster', 'Keeps its accumulated value when the rung goes false', 'Cannot be reset', 'Only counts down'], 'answer': 1, 'explain': 'RTO holds ACC across false rungs and needs an explicit RES to clear — used for cumulative runtime.'}], 6: [{'q': 'An FRL unit in a pneumatic system provides:', 'options': ['Filter, Regulator, Lubricator', 'Flow, Return, Load', 'Fast Reset Latch', 'Fault Relay Logic'], 'answer': 0, 'explain': 'The FRL conditions shop air: filters contaminants, regulates pressure, and adds lubrication mist for valves/cylinders.'}, {'q': 'Doubling a hydraulic cylinder bore area roughly does what to output force at the same pressure?', 'options': ['Halves it', 'Leaves it unchanged', 'Doubles it', 'Squares it'], 'answer': 2, 'explain': 'Force = Pressure × Area. Twice the area at the same PSI produces twice the force.'}, {'q': 'A pneumatic cylinder drifts back after stopping mid-stroke. The most likely cause is:', 'options': ['Air is compressible, so it cannot hold position rigidly', 'The PLC crashed', 'Low voltage', 'A blown fuse'], 'answer': 0, 'explain': 'Because air compresses, pneumatics cannot hold an intermediate position stiffly — hydraulics or a lock is needed for that.'}], 12: [{'q': 'During commissioning you bump-test a motor. What are you verifying?', 'options': ['Its color', 'Correct rotation direction before coupling the load', 'The paint finish', 'The nameplate font'], 'answer': 1, 'explain': 'A momentary bump confirms rotation direction so you do not run a pump/conveyor backward into the load.'}, {'q': 'A punch list at project handover is:', 'options': ['A list of employees', 'Outstanding items to fix before final acceptance', 'The lunch schedule', 'A parts catalog'], 'answer': 1, 'explain': 'The punch list captures remaining deficiencies the integrator must correct before the customer signs off.'}, {'q': 'System integration means:', 'options': ['Installing one PLC', 'Making sensors, drives, PLCs, HMI, safety, and networks work together as one coordinated machine', 'Only wiring power', 'Writing a manual'], 'answer': 1, 'explain': 'Integration is the discipline of tying every subsystem into a reliable, coordinated whole.'}, {'q': 'The best defense against a chaotic startup is:', 'options': ['Skipping documentation', 'A written commissioning checklist executed in order', 'Powering everything at once', 'Guessing'], 'answer': 1, 'explain': 'A staged checklist (power → I/O → safety → dry-run → loaded run) prevents damage and finds faults early.'}], 14: [{'q': 'In an edge/fog/cloud architecture, the CLOUD layer is best suited for:', 'options': ['Microsecond motion control', 'Long-term analytics, fleet dashboards, and machine learning', 'Directly switching a contactor', 'Reading a limit switch'], 'answer': 1, 'explain': 'The cloud handles big-data storage and analytics; real-time control stays at the edge where latency is low.'}, {'q': 'An MQTT broker’s job is to:', 'options': ['Generate electricity', 'Route published messages to subscribed clients by topic', 'Replace the PLC', 'Provide 480V power'], 'answer': 1, 'explain': 'The broker decouples publishers and subscribers, forwarding messages by topic — the heart of MQTT pub/sub.'}, {'q': 'A "digital twin" is:', 'options': ['A backup hard drive', 'A live virtual model of a physical asset fed by real data', 'A second operator', 'A spare PLC'], 'answer': 1, 'explain': 'A digital twin mirrors a real machine in software, enabling simulation, monitoring, and predictive analysis.'}], 15: [{'q': 'When using a clamp meter to read motor current without breaking the circuit, you clamp around:', 'options': ['All three conductors at once', 'A single conductor', 'The ground wire only', 'The conduit'], 'answer': 1, 'explain': 'Clamping all conductors cancels the fields and reads zero; clamp ONE conductor to measure its current.'}, {'q': 'A "voltage present but no current flow" reading on a de-energized load usually indicates:', 'options': ['A healthy circuit', 'An open load or downstream open (the circuit is broken)', 'A short circuit', 'Correct operation'], 'answer': 1, 'explain': 'Full source voltage with no current means the path is open — the load or a downstream connection is broken.'}, {'q': 'Before trusting any "dead" reading during LOTO, best practice is to:', 'options': ['Assume it is off', 'Verify the meter on a known-live source before and after (live-dead-live)', 'Skip the meter', 'Ask a coworker'], 'answer': 1, 'explain': 'Live-dead-live proves the meter works, so a "dead" reading truly means de-energized — never assume.'}], 18: [{'q': 'A certification roadmap should be prioritized primarily by:', 'options': ['Which has the coolest logo', 'Return on investment for your career path', 'Alphabetical order', 'Which is cheapest only'], 'answer': 1, 'explain': 'Pick credentials that open the roles you want and pay back their cost/effort — ROI, not vanity.'}, {'q': 'In a behavioral interview, the STAR method structures answers as:', 'options': ['Start, Talk, Argue, Rest', 'Situation, Task, Action, Result', 'Safety, Tools, Access, Report', 'Study, Test, Apply, Renew'], 'answer': 1, 'explain': 'STAR (Situation-Task-Action-Result) gives concrete, evidence-based answers interviewers can follow.'}, {'q': 'The strongest signal of hands-on competence in a portfolio is:', 'options': ['A long list of buzzwords', 'Documented projects: a wiring photo, a ladder program, a before/after fix', 'A fancy font', 'Number of pages'], 'answer': 1, 'explain': 'Concrete artifacts (programs, wiring, documented troubleshooting) prove skill far better than adjectives.'}]}
